//! Spec-compliance tests: Break Types & Paragraph Alignment
//! (ISO 29500-1 §17.3.3.1, §17.18.44)
//!
//! These tests verify our implementation against specific OOXML break type
//! and alignment constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/create_break_alignment.py`.

use stemma::{Alignment, BreakType, InlineNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/break-types";

// =========================================================================
// Break types (ISO 29500-1 §17.3.3.1)
// =========================================================================

/// ISO 29500-1 §17.3.3.1: `<w:br w:type="page"/>` is a page break.
#[test]
fn spec_page_break_type_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "break-types");
    let paras = common::all_paragraphs(&doc);

    // Paragraph 0: "Before page break" + PAGE break + "After page break"
    let p = &paras[0];
    let inlines = p.all_inlines_owned();
    let hard_breaks: Vec<&_> = inlines
        .iter()
        .filter_map(|i| match i {
            InlineNode::HardBreak(hb) => Some(hb),
            _ => None,
        })
        .collect();

    assert!(
        !hard_breaks.is_empty(),
        "paragraph 0 should contain at least one HardBreak for the page break, \
         got inlines: {:?}",
        inlines
            .iter()
            .map(std::mem::discriminant)
            .collect::<Vec<_>>()
    );

    assert_eq!(
        hard_breaks[0].break_type,
        BreakType::Page,
        "<w:br w:type=\"page\"/> should produce BreakType::Page, got {:?}",
        hard_breaks[0].break_type
    );
}

