/// ISO 29500-1 §17.3.3.1: A bare `<w:br/>` (no type attribute) defaults to
/// textWrapping — a line break. This should produce a HardBreak node.
#[test]
fn spec_line_break_is_default() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "break-types");
    let paras = common::all_paragraphs(&doc);

    // Paragraph 2: "Line break" + bare <w:br/>
    let p = &paras[2];
    assert!(
        common::paragraph_text(p).contains("Line break"),
        "paragraph 2 should contain 'Line break', got '{}'",
        common::paragraph_text(p)
    );

    let inlines = p.all_inlines_owned();
    let has_hard_break = inlines
        .iter()
        .any(|i| matches!(i, InlineNode::HardBreak(_)));

    assert!(
        has_hard_break,
        "A bare <w:br/> (textWrapping default) should produce a HardBreak node. \
         Paragraph inlines: {:?}",
        inlines
            .iter()
            .map(std::mem::discriminant)
            .collect::<Vec<_>>()
    );
}

// =========================================================================
// Alignment / ST_Jc completeness (ISO 29500-1 §17.18.44)
// =========================================================================
//
// Paragraph layout in fixture:
//  [0] "Left aligned"       — jc val="left"
//  [1] "Center aligned"     — jc val="center"
//  [2] "Right aligned"      — jc val="right"
//  [3] "Justified"          — jc val="both"
//  [4] "Distributed"        — jc val="distribute"
//  [5] "Start aligned"      — jc val="start"
//  [6] "End aligned"        — jc val="end"
//  [7] "Thai distribute"    — jc val="thaiDistribute"

/// ISO 29500-1 §17.18.44: Standard alignment values left, center, right, both.
///
/// These four values map directly to the Alignment enum variants.
#[test]
fn spec_alignment_left_center_right_justify() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "alignment-distribute");
    let paras = common::all_paragraphs(&doc);

    assert!(
        paras.len() >= 8,
        "fixture should have at least 8 paragraphs, got {}",
        paras.len()
    );

    // Paragraph 0: left
    assert!(
        common::paragraph_text(paras[0]).contains("Left aligned"),
        "paragraph 0 should be 'Left aligned', got '{}'",
        common::paragraph_text(paras[0])
    );
    assert_eq!(
        paras[0].align,
        Some(Alignment::Left),
        "jc val='left' should produce Alignment::Left, got {:?}",
        paras[0].align
    );

    // Paragraph 1: center
    assert!(
        common::paragraph_text(paras[1]).contains("Center aligned"),
        "paragraph 1 should be 'Center aligned', got '{}'",
        common::paragraph_text(paras[1])
    );
    assert_eq!(
        paras[1].align,
        Some(Alignment::Center),
        "jc val='center' should produce Alignment::Center, got {:?}",
        paras[1].align
    );

    // Paragraph 2: right
    assert!(
        common::paragraph_text(paras[2]).contains("Right aligned"),
        "paragraph 2 should be 'Right aligned', got '{}'",
        common::paragraph_text(paras[2])
    );
    assert_eq!(
        paras[2].align,
        Some(Alignment::Right),
        "jc val='right' should produce Alignment::Right, got {:?}",
        paras[2].align
    );

    // Paragraph 3: both (justify)
    assert!(
        common::paragraph_text(paras[3]).contains("Justified"),
        "paragraph 3 should be 'Justified', got '{}'",
        common::paragraph_text(paras[3])
    );
    assert_eq!(
        paras[3].align,
        Some(Alignment::Justify),
        "jc val='both' should produce Alignment::Justify, got {:?}",
        paras[3].align
    );
}

