/// ISO 29500-1 §17.18.44 / MS-OI29500 §2.1.45: `<w:jc w:val="start"/>`
/// maps to Left alignment (LTR context).
#[test]
fn spec_alignment_start_maps_to_left() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "alignment-distribute");
    let paras = common::all_paragraphs(&doc);

    // Paragraph 5: start
    assert!(
        common::paragraph_text(paras[5]).contains("Start aligned"),
        "paragraph 5 should be 'Start aligned', got '{}'",
        common::paragraph_text(paras[5])
    );
    assert_eq!(
        paras[5].align,
        Some(Alignment::Left),
        "jc val='start' should map to Alignment::Left (LTR context), got {:?}",
        paras[5].align
    );
}

